import json
import re
import os

# Debug why state extraction fails
businesses = locals().get('var_functions.query_db_44')

# Load from file if needed
if isinstance(businesses, str):
    print(f"Loading from: {businesses}")
    if os.path.exists(businesses):
        with open(businesses, 'r') as f:
            businesses = json.load(f)
    else:
        print("File path doesn't exist, trying alternative...")
        # List files in /tmp to find it
        import glob
        files = glob.glob('/tmp/*.json')
        print(f"Available files: {files}")
        if files:
            with open(files[0], 'r') as f:
                businesses = json.load(f)
        else:
            businesses = []
else:
    businesses = businesses or []

print(f"Total businesses: {len(businesses)}")

# Check a few sample businesses to debug
detected_states = {}
wifi_examples = []

for i, business in enumerate(businesses[:50]):  # Check first 50
    # Check WiFi
    wifi_status = None
    has_wifi = False
    attrs = business.get('attributes')
    if attrs and isinstance(attrs, dict):
        wifi_status = attrs.get('WiFi')
        if wifi_status and isinstance(wifi_status, str):
            wifi_clean = wifi_status.replace("u'", "").replace("'", "").lower()
            if wifi_clean not in ['no', 'none', 'nan', '']:
                has_wifi = True

    # Check state in description
    desc = business.get('description', '')
    if desc:
        # Try different patterns
        patterns = [
            r'\bin\s+[^,]+,\s*([A-Z]{2})\b',  # "in City, ST," pattern
            r'[,\s]\s*([A-Z]{2})\b',           # Previous pattern
            r'([A-Z]{2})\b.*$',                 # Last 2-letter code in string
        ]

        for pattern in patterns:
            match = re.search(pattern, desc)
            if match:
                state = match.group(1)
                detected_states[state] = detected_states.get(state, 0) + 1
                if has_wifi:
                    wifi_examples.append({
                        'name': business.get('name'),
                        'state': state,
                        'wifi': wifi_status
                    })
                break

print("States detected:", detected_states)
print("WiFi examples:", wifi_examples[:5])

# Now do full analysis
wifi_by_state = {}
for business in businesses:
    # Get WiFi status
    wifi_offered = False
    attrs = business.get('attributes')
    if attrs and isinstance(attrs, dict):
        wifi_status = attrs.get('WiFi')
        if wifi_status and isinstance(wifi_status, str):
            wifi_clean = wifi_status.replace("u'", "").replace("'", "").lower()
            if wifi_clean not in ['no', 'none', 'nan', '']:
                wifi_offered = True

    # Extract state
    if wifi_offered:
        desc = business.get('description', '')
        if desc:
            # Use the pattern that worked
            match = re.search(r'\bin\s+[^,]+,\s*([A-Z]{2})\b', desc)
            if match:
                state = match.group(1)
                wifi_by_state[state] = wifi_by_state.get(state, 0) + 1

print("Final WiFi by state:", wifi_by_state)

if wifi_by_state:
    top_state = max(wifi_by_state, key=wifi_by_state.get)
    top_count = wifi_by_state[top_state]
else:
    top_state = None
    top_count = 0

result = {
    'top_state': top_state,
    'top_state_count': top_count
}

print('__RESULT__:')
print(json.dumps(result))

